import { execution } from '@dynatrace-sdk/automation-utils';
import { problemsClient } from '@dynatrace-sdk/client-classic-environment-v2';

export default async function ({ executionId }) {
  const { input } = await fetch(`/platform/automation/v1/executions/${executionId}`).then((res) => res.json());

  try {
    const timeFrameMs = parseInt(input.timeFrameMinutes || 1440) * 60 * 1000;
    const from = Date.now() - timeFrameMs;
    const to = Date.now();

    let problemSelector = undefined;
    if (input.problemStatus && input.problemStatus.trim() !== '') {
      problemSelector = `status("${input.problemStatus}")`;
    }

    const response = await problemsClient.listProblems({
      problemSelector: problemSelector,
      from: from,
      to: to,
      limit: parseInt(input.maxResults || 50)
    });

    const problems = response.problems || [];

    console.log(`Retrieved ${problems.length} problems`);

    return {
      totalProblems: problems.length,
      problems: problems.map(p => ({
        problemId: p.problemId,
        displayId: p.displayId,
        title: p.title,
        status: p.status,
        severity: p.severity,
        startTime: new Date(p.startTime).toISOString(),
        endTime: p.endTime ? new Date(p.endTime).toISOString() : null
      }))
    };
  } catch (error) {
    console.error('Error fetching problems:', error);
    throw new Error(`Failed to fetch problems: ${error}`);
  }
}
